using QAHub.Api.Domain.Execution;namespace QAHub.Api.Tests;public sealed class ExecutionDomainTests{[Fact]public void FailedRequiresActualEvidenceAndReason(){Assert.Throws<ArgumentException>(()=>new TestRunAttempt(Guid.NewGuid(),1,ExecutionResult.Failed,"","","","qa"));}[Fact]public void PassedCanBeRecordedWithoutEvidence(){var x=new TestRunAttempt(Guid.NewGuid(),1,ExecutionResult.Passed,"","","","qa");Assert.Equal(ExecutionResult.Passed,x.Result);}[Fact]public void RerunKeepsIndependentAttemptNumber(){var id=Guid.NewGuid();var first=new TestRunAttempt(id,1,ExecutionResult.Failed,"actual","evidence","reason","qa");var second=new TestRunAttempt(id,2,ExecutionResult.Passed,"","","","qa");Assert.Equal(1,first.AttemptNumber);Assert.Equal(2,second.AttemptNumber);}}
